import os  # Import the operating system module so we will be able to use its path functions


def file_access(username):
    """Determine whether this user should have access"""
    return True


def read_file(filename, username=None):
    """Read a file and return the contents.

    :param filename: The name of the file.
    :type filename: str
    :returns: The content of the file as one long string.
    :rtype: str

    """
    # Make sure we are not trying to access a file that is in our python
    # source code folder!
    if os.path.abspath(filename).startswith(os.path.dirname(__file__)):
        raise ValueError("Cannot read from Python source code files.")
    
    if username and not file_access(username):  # Check user permissions
        return None

    with open(filename) as fp: 
        contents = fp.read()
    return contents